import{_ as s,o as t,c as o,ai as i}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"Auth Monitoring","description":"","frontmatter":{"summary":"Monitor OAuth expiry for model providers","read_when":["Setting up auth expiry monitoring or alerts","Automating Claude Code / Codex OAuth refresh checks"],"title":"Auth Monitoring"},"headers":[],"relativePath":"automation/auth-monitoring.md","filePath":"automation/auth-monitoring.md","lastUpdated":null}'),a={name:"automation/auth-monitoring.md"};function r(n,e,d,l,c,p){return t(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="auth-monitoring" tabindex="-1"><a class="header-anchor" href="#auth-monitoring">#</a> Auth monitoring</h1><p>OpenSoul exposes OAuth expiry health via <code>opensoul models status</code>. Use that for automation and alerting; scripts are optional extras for phone workflows.</p><h2 id="preferred-cli-check-portable" tabindex="-1"><a class="header-anchor" href="#preferred-cli-check-portable">#</a> Preferred: CLI check (portable)</h2><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> models</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --check</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Exit codes:</p><ul><li><code>0</code>: OK</li><li><code>1</code>: expired or missing credentials</li><li><code>2</code>: expiring soon (within 24h)</li></ul><p>This works in cron/systemd and requires no extra scripts.</p><h2 id="optional-scripts-ops-phone-workflows" tabindex="-1"><a class="header-anchor" href="#optional-scripts-ops-phone-workflows">#</a> Optional scripts (ops / phone workflows)</h2><p>These live under <code>scripts/</code> and are <strong>optional</strong>. They assume SSH access to the gateway host and are tuned for systemd + Termux.</p><ul><li><code>scripts/claude-auth-status.sh</code> now uses <code>opensoul models status --json</code> as the source of truth (falling back to direct file reads if the CLI is unavailable), so keep <code>opensoul</code> on <code>PATH</code> for timers.</li><li><code>scripts/auth-monitor.sh</code>: cron/systemd timer target; sends alerts (ntfy or phone).</li><li><code>scripts/systemd/opensoul-auth-monitor.{service,timer}</code>: systemd user timer.</li><li><code>scripts/claude-auth-status.sh</code>: Claude Code + OpenSoul auth checker (full/json/simple).</li><li><code>scripts/mobile-reauth.sh</code>: guided re‑auth flow over SSH.</li><li><code>scripts/termux-quick-auth.sh</code>: one‑tap widget status + open auth URL.</li><li><code>scripts/termux-auth-widget.sh</code>: full guided widget flow.</li><li><code>scripts/termux-sync-widget.sh</code>: sync Claude Code creds → OpenSoul.</li></ul><p>If you don’t need phone automation or systemd timers, skip these scripts.</p>',11)])])}const m=s(a,[["render",r]]);export{u as __pageData,m as default};
